+#[must_use]
+fn is_rich_markup_tag(tag_content: &str) -> bool {
+    if tag_content.starts_with('/') {
+        return true;
+    }
+    if tag_content.contains(' ') || tag_content.contains('=') {
+        return true;
+    }
+
+    let normalized = tag_content.to_ascii_lowercase();
+    matches!(
+        normalized.as_str(),
+        "bold"
+            | "dim"
+            | "italic"
+            | "underline"
+            | "strike"
+            | "blink"
+            | "reverse"
+            | "black"
+            | "red"
+            | "green"
+            | "yellow"
+            | "blue"
+            | "magenta"
+            | "cyan"
+            | "white"
+            | "default"
+            | "bright_black"
+            | "bright_red"
+            | "bright_green"
+            | "bright_yellow"
+            | "bright_blue"
+            | "bright_magenta"
+            | "bright_cyan"
+            | "bright_white"
+    )
